SELECT guest_id, COALESCE(first_name, '') || ' ' || COALESCE(last_name, '') AS full_name
FROM guests
ORDER BY guest_id;

SELECT DISTINCT first_name, last_name, phone_number
FROM guests
WHERE guest_id IN (SELECT guest_id FROM reservations);

SELECT first_name, last_name, email, phone_number, hire_date, rating, availability 
FROM servers 
WHERE server_id = 5;

SELECT first_name, last_name, loyalty_points 
FROM guests 
WHERE loyalty_points = (SELECT MAX(loyalty_points) FROM guests);

SELECT COUNT(DISTINCT guest_id) 
FROM reservations 
WHERE reservation_time BETWEEN 'YYYY-MM-DD HH:MM:SS' AND 'YYYY-MM-DD HH:MM:SS';

SELECT SUM(total_amount) AS total_treasure_chests_contents
FROM orders
WHERE order_time BETWEEN '2022-01-01' AND '2022-01-31';

SELECT preferred_contact_method, COUNT(*) AS Number_of_Guests
FROM guests
GROUP BY preferred_contact_method;

SELECT first_name, last_name
FROM guests
WHERE guest_id NOT IN (SELECT guest_id FROM reservations);

SELECT guest_id, first_name, last_name, email
FROM guests
ORDER BY first_name ASC;

SELECT guests.first_name, guests.last_name, guests.phone_number
FROM guests
INNER JOIN reservations ON guests.guest_id = reservations.guest_id;

SELECT first_name, last_name, email
FROM guests
WHERE guest_id IN (SELECT guest_id FROM reservations);

SELECT guest_id, first_name, last_name, email
FROM guests
WHERE guest_id IN (
    SELECT guest_id 
    FROM reservations
);
